    {
      "name": "CreateChannel",
      "purpose": "Handle create_channel command: create new channel with unique name, set caller as creator and first member.",
      "behavior": "Check channel name uniqueness in channels store; if unique, create channel record with creator and member list containing caller; return success or error.",
      "boundary": {
        "in_scope": ["name uniqueness check", "channel creation", "member initialization"],
        "out_of_scope": ["other commands", "message storage"]
      },
      "semantic_inputs": [
        {"name": "validated_data", "description": "Contains channel_name, user_id", "source": "parent input"},
        {"name": "channels", "description": "Channel data store", "source": "internal leaf access"}
      ],
      "semantic_outputs": [
        {"name": "create_result", "description": "Success or error response", "consumer": "parent"}
