    {"from": "parent", "to": "JoinChannel", "data": "validated_data", "note": "if command is join"},
    {"from": "SendMessage", "to": "parent", "data": "send_result", "note": "result from send"},
    {"from": "GetHistory", "to": "parent", "data": "history_result", "note": "result from history"},
    {"from": "CreateChannel", "to": "parent", "data": "create_result", "note": "result from create"},
    {"from": "JoinChannel", "to": "parent", "data": "join_result", "note": "result from join"},
    {"from": "parent", "to": "FormatResponse", "data": "command_result", "note": "format final output"},
    {"from": "FormatResponse", "to": "parent", "data": "output", "note": "final response"}
  ]
